.darma-loader-uiverse-indigo-dot-rotor__spinner {
  --R: 28px;
  --g1: var(--loader-color, #004dff) 96%, transparent;
  --g2: var(--loader-secondary-color, #d6d6fc) 96%, transparent;
  width: calc(2 * var(--R));
  height: calc(2 * var(--R));
  border-radius: 50%;
  display: grid;
  -webkit-mask: linear-gradient(#000 0 0);
  animation: darma-loader-uiverse-indigo-dot-rotor-indigoRotor 2s infinite linear;
}
.darma-loader-uiverse-indigo-dot-rotor__spinner::before,
.darma-loader-uiverse-indigo-dot-rotor__spinner::after {
  content: "";
  grid-area: 1 / 1;
  width: 50%;
  background:
    radial-gradient(farthest-side, var(--g1)) calc(var(--R) + .866 * var(--R) - var(--R)) calc(var(--R) - .5 * var(--R) - var(--R)),
    radial-gradient(farthest-side, var(--g2)) calc(var(--R) + .5 * var(--R) - var(--R)) calc(var(--R) - .866 * var(--R) - var(--R)),
    radial-gradient(farthest-side, var(--g1)) 0 calc(-1 * var(--R)),
    radial-gradient(farthest-side, var(--g2)) calc(-1 * var(--R)) 0;
  background-size: calc(2 * var(--R)) calc(2 * var(--R));
  background-repeat: no-repeat;
}
.darma-loader-uiverse-indigo-dot-rotor__spinner::after { transform: rotate(180deg); transform-origin: right; }
@keyframes darma-loader-uiverse-indigo-dot-rotor-indigoRotor { to { transform: rotate(-1turn); } }

